//  launch_sg2_metanet_only_generated
// ═══════════════════════════════════════════════════════════════════════

void launch_sg2_metanet_only_generated(
    torch::Tensor grad,
    torch::Tensor fwd_scan_out, torch::Tensor bwd_scan_out,
    torch::Tensor out_proj_fwd_W, torch::Tensor out_proj_bwd_W,
    torch::Tensor gru_Wz, torch::Tensor gru_bz,
    torch::Tensor gru_Wr, torch::Tensor gru_br,
    torch::Tensor gru_Wh, torch::Tensor gru_bh,
    torch::Tensor gru_state,
    torch::Tensor peer_query_Ws, torch::Tensor prod_keys_A, torch::Tensor prod_keys_B,
    torch::Tensor expert_W1, torch::Tensor expert_b1,
    torch::Tensor expert_W2, torch::Tensor expert_b2,
    torch::Tensor meta_output,
    float rescale,
    torch::Tensor expert_counts,
    int d_model, int d_inner_val,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts,
    int expert_prec_int
) {
    const int N = grad.numel();
    if (N == 0) return;

    ExpertPrecision expert_prec = static_cast<ExpertPrecision>(expert_prec_int);
    ArchTier hw_tier = get_arch_tier();
    if (hw_tier == ArchTier::HOPPER || hw_tier == ArchTier::BLACKWELL) {
        hw_tier = ArchTier::AMPERE;
    }

    const int grid = (N + SG2_DISPATCH_BLOCK - 1) / SG2_DISPATCH_BLOCK;
    const int block = SG2_DISPATCH_BLOCK;

    if (expert_prec == ExpertPrecision::FP32 && hw_tier == ArchTier::GENERIC && d_inner_val != 16) {
        AT_DISPATCH_FLOATING_TYPES_AND2(at::ScalarType::Half, at::ScalarType::BFloat16, grad.scalar_type(), "sg2_metanet", ([&] {
            sg2_metanet_fp32_generic_kernel<scalar_t><<<grid, block>>>(
                grad.data_ptr<scalar_t>(),
                fwd_scan_out.data_ptr<float>(),
                bwd_scan_out.data_ptr<float>(),
                out_proj_fwd_W.data_ptr<float>(),
                out_proj_bwd_W.data_ptr<float>(),
                gru_Wz.data_ptr<float>(), gru_bz.data_ptr<float>(),
                gru_Wr.data_ptr<float>(), gru_br.data_ptr<float>(),
                gru_Wh.data_ptr<float>(), gru_bh.data_ptr<float>(),
                gru_state.data_ptr<float>(),
                peer_query_Ws.data_ptr<float>(),
                prod_keys_A.data_ptr<float>(),
                prod_keys_B.data_ptr<float>(),
                expert_W1.data_ptr<float>(),
                expert_b1.data_ptr<float>(),
                expert_W2.data_ptr<float>(),
                expert_b2.data_ptr<float>(),
                meta_output.data_ptr<float>(),
                rescale,
                expert_counts.defined() ? expert_counts.data_ptr<int>() : nullptr,
                N, d_model, d_inner_val,
                gru_hidden, num_heads, pk_dim,
                expert_hidden, num_experts);
        }));
    } else if (expert_prec == ExpertPrecision::FP32 && hw_tier == ArchTier::GENERIC && d_inner_val == 16) {
        AT_DISPATCH_FLOATING_TYPES_AND2(at::ScalarType::Half, at::ScalarType::BFloat16, grad.scalar_type(), "sg2_metanet", ([&] {
            sg2_metanet_fp32_generic_d16_kernel<scalar_t><<<grid, block>>>(
                grad.data_ptr<scalar_t>(),
                fwd_scan_out.data_ptr<float>(),
                bwd_scan_out.data_ptr<float>(),
                out_proj_fwd_W.data_ptr<float>(),
                out_proj_bwd_W.data_ptr<float>(),
                gru_Wz.data_ptr<float>(), gru_bz.data_ptr<float>(),
                gru_Wr.data_ptr<float>(), gru_br.data_ptr<float>(),
                gru_Wh.data_ptr<float>(), gru_bh.data_ptr<float>(),
                gru_state.data_ptr<float>(),
                peer_query_Ws.data_ptr<float>(),
                prod_keys_A.data_ptr<float>(),
                prod_keys_B.data_ptr<float>(),
                expert_W1.data_ptr<float>(),
                expert_b1.data_ptr<float>(),
                expert_W2.data_ptr<float>(),
                expert_b2.data_ptr<float>(),
                meta_output.data_ptr<float>(),
                rescale,
                expert_counts.defined() ? expert_counts.data_ptr<int>() : nullptr,
                N, d_model, d_inner_val,
                gru_hidden, num_heads, pk_dim,
                expert_hidden, num_experts);
        }));
    } else if (expert_prec == ExpertPrecision::FP32 && hw_tier == ArchTier::AMPERE && d_inner_val != 16) {
        AT_DISPATCH_FLOATING_TYPES_AND2(at::ScalarType::Half, at::ScalarType::BFloat16, grad.scalar_type(), "sg2_metanet", ([&] {
            sg2_metanet_fp32_sm80_kernel<scalar_t><<<grid, block>>>(
