// ═══════════════════════════════════════════════════════════════════════
//  launch_sg2_adam_only_generated
//
//  Adam-only step (no meta-net). Simple dispatch.
// ═══════════════════════════════════════════════════════════════════════

void launch_sg2_adam_only_generated(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor exp_avg,
    torch::Tensor exp_avg_sq,
    float beta1, float beta2,
    float lr, float wd, float eps,
    float bc1, float bc2,
    int state_prec_int
) {
    const int N = param.numel();
    if (N == 0) return;

    StatePrecision state_prec = static_cast<StatePrecision>(state_prec_int);
    const int grid = (N + SG2_DISPATCH_BLOCK - 1) / SG2_DISPATCH_BLOCK;

    // Adam-only uses the fused GrokAdamW kernels with alpha=0, lamb=0
    // (effectively disabling the EMA filter and amplification).
    // Dispatch to Q4 variant if CONFIG4 state, else standard FP32.
    if (state_prec == StatePrecision::CONFIG4) {
        // Use grokadamw_q4_step (from grokadamw_generated.cu)
        // launch_grokadamw_q4_step(param, ...);
    } else {
        // Use standard FP32 Adam
        // launch_fused_grokadamw_step(param, ...);
    }
}

// ═══════════════════════════════════════════════════════════════════════
//  launch_sg2_persistent_scan_generated
// ═══════════════════════════════════════════════════════════════════════

void launch_sg2_persistent_scan_generated(
    torch::Tensor x_sorted,
    torch::Tensor in_proj_W, torch::Tensor dt_proj_W, torch::Tensor dt_proj_b,
    torch::Tensor B_proj_W, torch::Tensor C_proj_W,
    torch::Tensor A_log, torch::Tensor D_param, torch::Tensor rope_freq,
    torch::Tensor scan_output, torch::Tensor scan_state,
    torch::Tensor initial_state,
    int N, int d_model, int d_inner_val, int d_state, int reverse,
    int state_prec_int
) {
    if (N == 0) return;

    StatePrecision state_prec = static_cast<StatePrecision>(state_prec_int);
    ArchTier hw_tier = get_arch_tier();
    if (hw_tier == ArchTier::HOPPER || hw_tier == ArchTier::BLACKWELL) {
        hw_tier = ArchTier::AMPERE;
    }

    if (state_prec == StatePrecision::FP32 && hw_tier == ArchTier::GENERIC && d_inner_val != 16) {
        // Selected kernel: sg2_persistent_scan_F_generic_kernel
        sg2_persistent_scan_F_generic_kernel<<<1, d_inner_val>>>(
            x_sorted.data_ptr<float>(),
            in_proj_W.data_ptr<float>(), dt_proj_W.data_ptr<float>(), dt_proj_b.data_ptr<float>(),
            B_proj_W.data_ptr<float>(), C_proj_W.data_ptr<float>(),
            A_log.data_ptr<float>(), D_param.data_ptr<float>(), rope_freq.data_ptr<float>(),
            scan_output.data_ptr<float>(),
            scan_state.defined() ? scan_state.data_ptr<float>() : nullptr,
            initial_state.defined() ? initial_state.data_ptr<float>() : nullptr,
            N, d_model, d_inner_val, d_state, reverse);
    } else if (state_prec == StatePrecision::FP32 && hw_tier == ArchTier::GENERIC && d_inner_val == 16) {
        // Selected kernel: sg2_persistent_scan_F_generic_d16_kernel
